import{_ as n,C as s,o as d,c as p,a1 as r,j as o,a as t,E as i,w as l}from"./chunks/framework.BX4nIuL2.js";const w=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/8CNC_manufacture/cncprogram.md","filePath":"courses/fab-course/doc/8CNC_manufacture/cncprogram.md"}'),c={name:"courses/fab-course/doc/8CNC_manufacture/cncprogram.md"};function u(h,e,m,f,g,b){const a=s("font");return d(),p("div",null,[e[17]||(e[17]=r('<p>After design in fusion electronics,we can switch to 3D PCB in the command of &quot;Switch/view 3D PCB&quot; <img src="https://gitlab.com/picbed/bed/uploads/e4bb6bbd94d1481963d0a4cba4b02990/pcbto3d.png" alt=""></p><p><strong>Remind:This method just for single layer PCB board.</strong></p><h2 id="_1-choice-model" tabindex="-1">1 .Choice model <a class="header-anchor" href="#_1-choice-model" aria-label="Permalink to &quot;1 .Choice model&quot;">​</a></h2><p>We need use &quot;manufacture&quot; function, so switch from &quot;3D PCB&quot; to &quot;manufacture&quot; <img src="https://gitlab.com/picbed/bed/uploads/fcd4df97a95a98e36bb267948af5654f/WX20201016-164305_2x.png" alt=""></p><p>We can just show <strong>board</strong> and <strong>1-copper</strong>. (Hidden another layer:16 copper(bottom copper),1 solder masker,16 soler masker, Packages(electronics components)) <img src="https://gitlab.com/picbed/bed/uploads/fcd4df97a95a98e36bb267948af5654f/WX20201016-164305_2x.png" alt=""></p><h2 id="_2-setup" tabindex="-1">2. Setup <a class="header-anchor" href="#_2-setup" aria-label="Permalink to &quot;2. Setup&quot;">​</a></h2><p>In this step ,we should tell the machine the stock size of material and the direction. <img src="https://gitlab.com/picbed/bed/uploads/b3af7d3978dbb51f4b1a762efaa9561e/ezgif.com-video-to-gif.gif" alt=""><a href="https://help.autodesk.com/view/fusion360/ENU/?guid=Fusion_CAM_how_to_create_setup_html" target="_blank" rel="noreferrer">More detail About Set up</a></p><h2 id="_3-process-in-fusion-cam" tabindex="-1">3. Process in Fusion CAM <a class="header-anchor" href="#_3-process-in-fusion-cam" aria-label="Permalink to &quot;3. Process in Fusion CAM&quot;">​</a></h2><p>Now we need 4 steps to process our PCB boards</p><ul><li>Step1: Milling the electrical interconnections path;</li><li>Step2:Drilling the hole;</li><li>Step3:First time Milling the profile of the PCB board;</li><li>Step4:Second time Milling the profile of the PCB board;</li></ul><h4 id="_3-1-step1-milling-the-electrical-interconnections-path" tabindex="-1">3.1 Step1: Milling the electrical interconnections path <a class="header-anchor" href="#_3-1-step1-milling-the-electrical-interconnections-path" aria-label="Permalink to &quot;3.1 Step1: Milling the  electrical interconnections path&quot;">​</a></h4><p>In this step ,we need use <a href="http://help.autodesk.com/view/fusion360/ENU/?guid=GUID223F93A7-F88E-4359-B02D-B0C2F11AFA8B" target="_blank" rel="noreferrer">&quot;Milling-2D-Trace &quot;command</a></p><p><img src="https://gitlab.com/picbed/bed/uploads/02427a9226e61e3704ca218915db83ea/settingtrace.png" alt=""> Now we need setting</p><ul><li>Tool &amp; Feed&amp;Speed</li><li>Geometry</li><li>Height</li><li>Pass</li></ul><h6 id="_3-1-1-tool-feed-speed" tabindex="-1">3.1.1 Tool &amp; Feed&amp;Speed <a class="header-anchor" href="#_3-1-1-tool-feed-speed" aria-label="Permalink to &quot;3.1.1 Tool &amp; Feed&amp;Speed&quot;">​</a></h6><p>We can click &quot;Tool/Select &quot; to setting the tool <img src="https://gitlab.com/picbed/bed/uploads/59aa639b69f64af2268352a44175d618/trace1.png" alt=""></p><p>How to confirm <a href="http://help.autodesk.com/view/fusion360/ENU/?guid=GUIDA0197982-0082-45AF-B848-8D62CAF57C49" target="_blank" rel="noreferrer">the parameter of cutter?</a></p><ul><li>Type: we need cut the copper on the surface ,so we choice &quot;flat end mill&quot;</li><li>Paramenter:We use the 7pin connector, the gap betweeen two pins is 2.54mm,after calculate,we find the space for electrical interconnections path is 1.01mm <ul><li>To avoid the overlap too mach,red path and blue path, we can choice the cutter small then 1mm, for example 0.8mm,0.6mm,0.4mm</li><li>If too small, the cutter is easy to broken;</li><li>Finial we choice 0.6mm flat end milling cutter</li></ul></li></ul><p><img src="https://gitlab.com/picbed/bed/uploads/38c538f83f64b4ca9f354cb7186f1f52/electropaht2.png" alt=""></p><p>The following is how to setting tool parameter in software</p><p><img src="https://gitlab.com/picbed/bed/uploads/a8decfcdbef2d919dde7add51a055f56/choicecutter2.png" alt=""><a href="http://help.autodesk.com/view/fusion360/ENU/?guid=GUID223F93A7-F88E-4359-B02D-B0C2F11AFA8B" target="_blank" rel="noreferrer">Another parameter setting</a></p>',21)),o("ul",null,[o("li",null,[e[1]||(e[1]=t("Coolcant:because we just process thin copper and resin,so don't need use any thing ,just choice disabled. ",-1)),i(a,{color:"Blue"},{default:l(()=>[...e[0]||(e[0]=[t("For plastic ,small copper,aluminum,we don't need coolant, but if we process steel and similar metal,we need coolant",-1)])]),_:1})]),o("li",null,[e[3]||(e[3]=t("Spindle Speed(The rotational speed of the spindle expressed in Rotations Per Minute (RPM)):",-1)),i(a,{color:"Blue"},{default:l(()=>[...e[2]||(e[2]=[t("Our machine's speed is 1000rpm(only one speed),so choice 1000rpm;",-1)])]),_:1})]),o("li",null,[e[5]||(e[5]=t("Surface Speed(The speed which the material moves past the cutting edge of the tool (SFM or m/min)):",-1)),i(a,{color:"Blue"},{default:l(()=>[...e[4]||(e[4]=[t("It would calculate by software according to cutter diameter and spindle speed: Surface speed =cutter diameter X spindle speed",-1)])]),_:1})]),o("li",null,[e[7]||(e[7]=t("Ramp Spindle Speed - The rotational speed of the spindle when performing ramp movements",-1)),i(a,{color:"Blue"},{default:l(()=>[...e[6]||(e[6]=[t("Same as spindle speed ,because the machine just one speed",-1)])]),_:1})]),o("li",null,[e[9]||(e[9]=t("Cutting Feedrate - Feedrate used in regular cutting moves. Expressed as Inches/Min (IPM) or MM/Min",-1)),i(a,{color:"Blue"},{default:l(()=>[...e[8]||(e[8]=[t("According to experience,60mm/min is available",-1)])]),_:1})]),o("li",null,[e[11]||(e[11]=t("Feed per Tooth - The cutting feedrate expressed as the feed per tooth (FPT)",-1)),i(a,{color:"Blue"},{default:l(()=>[...e[10]||(e[10]=[t("It wpuld calculate by software automatic",-1)])]),_:1})]),o("li",null,[e[12]||(e[12]=t("Lead-In Feedrate - Feed used when leading in to a cutting move.",-1)),i(a,{color:"Blue"})]),o("li",null,[e[13]||(e[13]=t("Lead-Out Feedrate - Feed used when leading out from a cutting move",-1)),i(a,{color:"Blue"})]),o("li",null,[e[14]||(e[14]=t("Ramp Feedrate - Feed used when doing helical ramps into stock",-1)),i(a,{color:"Blue"})]),o("li",null,[e[15]||(e[15]=t("Plunge Feedrate - Feed used when plunging into stock",-1)),i(a,{color:"Blue"})]),o("li",null,[e[16]||(e[16]=t("Feed per Revolution - The plunge feedrate expressed as the feed per revolution",-1)),i(a,{color:"Blue"})])]),e[18]||(e[18]=r('<p><img src="https://gitlab.com/picbed/bed/uploads/59aa639b69f64af2268352a44175d618/trace1.png" alt=""></p><h6 id="_3-1-2-geometry" tabindex="-1">3.1.2 Geometry <a class="header-anchor" href="#_3-1-2-geometry" aria-label="Permalink to &quot;3.1.2 Geometry&quot;">​</a></h6><p>Function define:Select any 3D Edge or Sketch to define the machining curve. In this case, we just choice the following 16 chains. <img src="https://gitlab.com/picbed/bed/uploads/ff3db822de33e332524da8ef95dbdae2/trace2.png" alt=""></p><h6 id="_3-1-3-height" tabindex="-1">3.1.3 Height <a class="header-anchor" href="#_3-1-3-height" aria-label="Permalink to &quot;3.1.3 Height&quot;">​</a></h6><ul><li>Clearance HeightThe Clearance height is the first height the tool rapids to on its way to the start of the tool path.</li><li>Retract height: incremental offset from the Retract Height.</li><li>Feed height: incremental offset from the Feed Height.</li><li>Top height: incremental offset from the Top Height.</li><li>Bottom height: incremental offset from the Bottom Height.</li><li>Model top: incremental offset from the Model Top.</li><li>Model bottom: incremental offset from the Model Bottom.</li><li>Stock top: incremental offset from the Stock Top.</li><li>Stock bottom: incremental offset from the Stock Bottom.</li><li>Selected contour(s): incremental offset from a Contour selected on the model.</li><li>Selection: incremental offset from a Point (vertex), Edge or Face selected on the model.</li><li>Origin (absolute): absolute offset from the Origin that is defined in either the Setup or in Tool Orientation within the specific operation.</li></ul><p>In our case ,parameter is the following:</p><p><img src="https://gitlab.com/picbed/bed/uploads/82ee1398e35b3a516b2ba163f695f498/trace3.png" alt=""></p><h6 id="_3-1-4-pass" tabindex="-1">3.1.4 Pass <a class="header-anchor" href="#_3-1-4-pass" aria-label="Permalink to &quot;3.1.4 Pass&quot;">​</a></h6><p>In this case ,we choice Right (conventional milling) <img src="https://gitlab.com/picbed/bed/uploads/8cbfc9296502e6f2f2eb0c0f49fdf2a9/trace4.png" alt=""></p><h4 id="_3-1-5-simulate" tabindex="-1">3.1.5 Simulate <a class="header-anchor" href="#_3-1-5-simulate" aria-label="Permalink to &quot;3.1.5 Simulate&quot;">​</a></h4><p>We can use &quot;simulate&quot; command to check if the NC program has any problem <img src="https://gitlab.com/picbed/bed/uploads/6100eddc0e5f98fcb0fc28dd9eaec1d2/WX20201017-100418_2x.png" alt=""><img src="https://gitlab.com/picbed/bed/uploads/369d0e6b1ab4aeccc900c33c6ef9bfed/ezgif.com-video-to-gif-3.gif" alt=""></p><h4 id="_3-1-6-output-nc-program" tabindex="-1">3.1.6 Output NC program <a class="header-anchor" href="#_3-1-6-output-nc-program" aria-label="Permalink to &quot;3.1.6 Output NC program&quot;">​</a></h4><p>If simulate is OK,we can use Create NC program and then output.</p><p><img src="https://gitlab.com/picbed/bed/uploads/482e3a87a8d383ba76893f2d9c05df2b/551602834162_.pic_hd.jpg" alt=""><strong>Remind:we need choice GBRL according to our machine</strong></p><h4 id="_3-2-step2-drilling-the-hole" tabindex="-1">3.2 Step2: Drilling the hole <a class="header-anchor" href="#_3-2-step2-drilling-the-hole" aria-label="Permalink to &quot;3.2 Step2: Drilling the hole&quot;">​</a></h4><p>In this step ,we need use <a href="http://help.autodesk.com/view/fusion360/ENU/?guid=Fusion_CAM_reference_drill_drill_standard_html" target="_blank" rel="noreferrer">&quot;Drilling &quot;command</a></p><p>Reference from &quot;3.1.1 Tool &amp; Feed&amp;Speed&quot;,we can choice drilling cutter &quot;Φ0.8mm&quot;.</p><p><img src="https://gitlab.com/picbed/bed/uploads/cbfaafce9066a43bd7d37d56f171c909/drillcutter22.png" alt=""></p><p>The Geometry of this step is the 15 holes we need process, choice it one by one. <img src="https://gitlab.com/picbed/bed/uploads/8212daf3572cd25198d62049193f70af/WX20201020-092639_2x.png" alt=""> About height, reference 3.1.3 ,and choice one by one ,the following is for reference.</p><p><img src="https://gitlab.com/picbed/bed/uploads/b2870260cc9960e2415485f59dbe43e1/WX20201020-093248_2x.png" alt=""></p><p>In this step, the method of Passs,Simulate,Output NC programis same with &quot;3.1&quot;, so just reference &quot;3.1.4Passs&quot;,&quot; 3.1.5 Simulate&quot;, &quot;3.1.6Output NC program&quot;</p><h4 id="_3-3-step3-milling-the-profile" tabindex="-1">3.3 Step3: Milling the profile <a class="header-anchor" href="#_3-3-step3-milling-the-profile" aria-label="Permalink to &quot;3.3 Step3: Milling the profile&quot;">​</a></h4><p>Ever time we can just cut the deep less than 1mm, but the thickness of our board is 1.5mm, so we need process two times(first 0.8mm, second 1.5mm) and output 2 NC programs.</p><p>In this step ,we need use <a href="http://help.autodesk.com/view/fusion360/ENU/?contextId=MFG-REF-2D-CONTOUR-CMD" target="_blank" rel="noreferrer">&quot;Milling/2D/2D Contour&quot;command</a></p><p>Tool we choice 0.8mm flat end milling cutter. the feed and speed reference the following.</p><p><img src="https://gitlab.com/picbed/bed/uploads/9321d81cb5f603a45ef5b1726669b16c/millprofile.png" alt=""> The Geometry just choice the profile of the PCB board. <img src="https://gitlab.com/picbed/bed/uploads/2573ce01aad48e914a5e407d8510918a/profile2.png" alt=""></p><p><img src="https://gitlab.com/picbed/bed/uploads/5e40c9f9f6dddb776ef3716949661744/WX20201020-094347_2x.png" alt=""> The only different for first 2D Contour and second 2D Contour is the above &quot;Bottom Height&quot;</p><p>In this step, the method of Passs,Simulate,Output NC programis same with &quot;3.1&quot;, so just reference &quot;3.1.4Passs&quot;,&quot; 3.1.5 Simulate&quot;, &quot;3.1.6Output NC program&quot;</p><p>We finish the NC data program. In next step,we need use CNC to manufacture it.</p><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ul><li><a href="https://help.autodesk.com/view/fusion360/ENU/?guid=GUID-BEC5DEA9-AC3E-4FA8-998E-4AE8CD0D0B1E" target="_blank" rel="noreferrer">Autodesk Fusion 360 manufacture(CAM) detail </a></li></ul><hr><p><strong>This document support by Bob Wu and Ciel Luo；thanks for XiaoWu&#39;s kind support 20201020</strong></p>',33))])}const C=n(c,[["render",u]]);export{w as __pageData,C as default};
